## Logging Strategy

### Tracing Macros

```rust
use crate::observability::{LogEntry, LogLevel};

impl DistributedRegionRecord {
    /// Logs a state transition with full context.
    fn log_transition(&self, transition: &StateTransition) {
        let entry = LogEntry::new(LogLevel::Info, "distributed_region_transition")
            .with_field("region_id", self.id.to_string())
            .with_field("from_state", transition.from.to_string())
            .with_field("to_state", transition.to.to_string())
            .with_field("reason", format!("{:?}", transition.reason))
            .with_field("timestamp", transition.timestamp.as_millis().to_string());

        // Additional context based on transition type
        match &transition.reason {
            TransitionReason::QuorumReached { replicas, required } => {
                entry
                    .with_field("replicas", replicas.to_string())
                    .with_field("required", required.to_string());
            }
            TransitionReason::ReplicaLost { replica_id, remaining } => {
                entry
                    .with_field("lost_replica", replica_id.clone())
                    .with_field("remaining_replicas", remaining.to_string());
            }
            TransitionReason::RecoveryComplete { symbols_used, duration_ms } => {
                entry
                    .with_field("symbols_used", symbols_used.to_string())
                    .with_field("recovery_duration_ms", duration_ms.to_string());
            }
            _ => {}
        }
    }

    /// Logs quorum state changes.
    fn log_quorum_change(&self, action: &str, replica_id: &str) {
        let entry = LogEntry::new(LogLevel::Debug, "distributed_region_quorum")
            .with_field("region_id", self.id.to_string())
            .with_field("action", action)
            .with_field("replica_id", replica_id)
            .with_field("current_quorum", self.current_quorum().to_string())
            .with_field("has_quorum", self.has_quorum().to_string());
    }
}

// Log level guidelines:
// - TRACE: Every state query, replica heartbeat
// - DEBUG: Quorum calculations, replica status changes
// - INFO:  State transitions, recovery events
// - WARN:  Degraded entry, quorum loss, replica suspected
// - ERROR: Recovery failure, invalid transitions, configuration errors
